/* ── CSV ─────────────────────────────────────────────────────────────────── */
const esc=v=>{const s=String(v??'');return s.includes(',')||s.includes('"')?`"${s.replace(/"/g,'""')}"`:s;};
const pLine=line=>{const r=[];let cur='',inQ=false;for(let i=0;i<line.length;i++){const c=line[i];if(c==='"'){if(inQ&&line[i+1]==='"'){cur+='"';i++;}else inQ=!inQ;}else if(c===','&&!inQ){r.push(cur);cur='';}else cur+=c;}r.push(cur);return r;};
const genCSV=client=>{let csv='';csv+=`PROFILE\nfirstName,lastName,email,phone,address,dob,social,clientType,recommendedBy,partnerFirst,partnerLast\n${[client.firstName,client.lastName,client.email,client.phone||'',client.address||'',client.dob||'',client.social||'',client.clientType||'',client.recommendedBy||'',client.partnerFirst||'',client.partnerLast||''].map(esc).join(',')}\n`;csv+=`\nINCOME\nperson,label,gross,net,frequency\n`;(client.incomeStreams||[]).forEach(s=>{csv+=`${[s.person,s.label,s.gross,s.net,s.freq].map(esc).join(',')}\n`;});csv+=`\nBILLS\nname,assignedTo,cost,type,frequency,dueDay,splitP1,splitP2\n`;(client.bills||[]).forEach(b=>{csv+=`${[b.name,b.assignedTo,b.cost,b.type,b.freq,b.dueDay||'',b.split?.p1??50,b.split?.p2??50].map(esc).join(',')}\n`;});csv+=`\nDEBT\nname,balance,apr,minPayment,limit,hasPromo,promoBalance,promoRate,promoEndDate,owedBy\n`;(client.cards||[]).forEach(c=>{csv+=`${[c.name,c.balance,c.apr,c.min,c.limit,c.promo?'true':'false',c.promoBalance||0,c.promoRate||0,c.promoEnd||'',c.owedBy||'joint'].map(esc).join(',')}\n`;});csv+=`\nASSETS\nchecking,savings,retirement,vehicle,realEstate\n${[client.assets?.checking,client.assets?.savings,client.assets?.retirement,client.assets?.vehicle,client.assets?.realEstate].map(esc).join(',')}\n`;csv+=`\nLIABILITIES\ncreditCards,vehicleLoan,studentLoan,personalLoan\n${[client.liabilities?.creditCards,client.liabilities?.vehicle,client.liabilities?.student,client.liabilities?.personal].map(esc).join(',')}\n`;return csv;};
const dlCSV=(csv,name)=>{const blob=new Blob([csv],{type:"text/csv"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=name;a.click();URL.revokeObjectURL(url);};
const expCSV=client=>dlCSV(genCSV(client),`${client.firstName}_${client.lastName}_GA.csv`);
const expAllCSV=clients=>dlCSV(clients.map(c=>`===== CLIENT: ${c.firstName} ${c.lastName} =====\n${genCSV(c)}`).join('\n\n'),'Golden_Anchor_All_Clients.csv');
const dlTmpl=()=>dlCSV(`PROFILE\nfirstName,lastName,email,phone,address,dob,social,clientType,recommendedBy,partnerFirst,partnerLast\nJohn,Doe,john@email.com,(305) 555-0000,"123 Main St Miami FL",1990-01-01,123-45-6789,financeOnly,Referral,,\n\nINCOME\nperson,label,gross,net,frequency\np1,Main Job,5000,3800,biweekly\n\nBILLS\nname,assignedTo,cost,type,frequency,dueDay,splitP1,splitP2\nRent,joint,1800,regular,monthly2,1,50,50\n\nDEBT\nname,balance,apr,minPayment,limit,hasPromo,promoBalance,promoRate,promoEndDate,owedBy\nChase Sapphire,5000,28.5,120,8000,false,0,0,,joint\n\nASSETS\nchecking,savings,retirement,vehicle,realEstate\n2500,5000,8000,18000,0\n\nLIABILITIES\ncreditCards,vehicleLoan,studentLoan,personalLoan\n5000,14000,0,0\n`,"golden_anchor_template.csv");
const parseCSV=(text,existing=null)=>{const lines=text.split('\n').map(l=>l.trim());let sec=null,hdr=null;const d={profile:null,income:[],bills:[],debt:[],assets:null,liabilities:null};for(const line of lines){if(!line)continue;const up=line.toUpperCase();if(['PROFILE','INCOME','BILLS','DEBT','ASSETS','LIABILITIES'].includes(up)){sec=up;hdr=null;continue;}if(!sec)continue;if(line.startsWith('==='))continue;const vals=pLine(line);if(!hdr){hdr=vals;continue;}const obj={};hdr.forEach((h,i)=>obj[h.trim()]=(vals[i]||'').trim());if(sec==='PROFILE')d.profile=obj;else if(sec==='INCOME'&&obj.label)d.income.push(obj);else if(sec==='BILLS'&&obj.name)d.bills.push(obj);else if(sec==='DEBT'&&obj.name)d.debt.push(obj);else if(sec==='ASSETS')d.assets=obj;else if(sec==='LIABILITIES')d.liabilities=obj;}
const p=d.profile||{};return mig({...(existing||{}),firstName:p.firstName||'',lastName:p.lastName||'',email:p.email||'',phone:p.phone||'',address:p.address||'',dob:p.dob||'',social:p.social||'',clientType:p.clientType||'financeOnly',recommendedBy:p.recommendedBy||'',partnerFirst:p.partnerFirst||null,partnerLast:p.partnerLast||null,id:existing?.id||gid(),incomeStreams:d.income.map((s,i)=>({id:gid()+i,person:s.person||'p1',label:s.label,gross:+s.gross||0,net:+s.net||0,freq:s.frequency||s.freq||'monthly2'})),bills:d.bills.map((b,i)=>({id:gid()+i,name:b.name,assignedTo:b.assignedTo||'joint',cost:+b.cost||0,type:b.type||'regular',freq:b.frequency||b.freq||'monthly2',dueDay:+b.dueDay||1,split:{p1:+(b.splitP1??50),p2:+(b.splitP2??50)}})),cards:d.debt.map((c,i)=>({id:gid()+i,name:c.name,balance:+c.balance||0,apr:+c.apr||0,min:+(c.minPayment||c.min)||0,limit:+c.limit||0,promo:c.hasPromo==='true',promoBalance:+c.promoBalance||0,promoRate:+c.promoRate||0,promoEnd:c.promoEndDate||'',owedBy:c.owedBy||'joint'})),assets:d.assets?{checking:+d.assets.checking||0,savings:+d.assets.savings||0,retirement:+d.assets.retirement||0,vehicle:+d.assets.vehicle||0,realEstate:+d.assets.realEstate||0}:(existing?.assets||{checking:0,savings:0,retirement:0,vehicle:0,realEstate:0}),liabilities:d.liabilities?{creditCards:+d.liabilities.creditCards||0,vehicle:+(d.liabilities.vehicleLoan||0),student:+(d.liabilities.studentLoan||0),personal:+(d.liabilities.personalLoan||0)}:(existing?.liabilities||{creditCards:0,vehicle:0,student:0,personal:0})});};

/* ── REMINDERS ───────────────────────────────────────────────────────────── */
function getClientRem(clients){const today=new Date();const day=today.getDate();const out=[];clients.forEach(c=>{(c.bills||[]).forEach(b=>{if(b.type!=="annual"&&b.dueDay){const diff=b.dueDay>=day?b.dueDay-day:b.dueDay+(31-day);if(diff<=7)out.push({clientName:`${c.firstName} ${c.lastName}`,clientId:c.id,name:b.name,dueDay:b.dueDay,amount:toM(b.cost,b.freq||"monthly2"),type:"bill",task:"Bill Due",daysUntil:diff});}});(c.cards||[]).forEach(cc=>{if(cc.min>0)out.push({clientName:`${c.firstName} ${c.lastName}`,clientId:c.id,name:cc.name,dueDay:null,amount:cc.min,type:"card",task:"Card Min",daysUntil:null});});});return out;}
function getAdvRem(clients,settings){const today=new Date();const out=[];clients.forEach(c=>{const snaps=c.monthSnapshots||[];if(settings.reminderAdvisor?.noContact){const last=snaps[snaps.length-1];const days=last?.savedAt?Math.floor((today-new Date(last.savedAt))/86400000):(snaps.length===0?999:0);if(days>=(settings.noContactDays||30))out.push({type:"noContact",priority:days>60?"high":"med",clientName:`${c.firstName} ${c.lastName}`,detail:`Last review ${days===999?"never":`${days} days ago`}`,task:"No Contact"});}if(settings.reminderAdvisor?.highDebt){const net=sumN(c.incomeStreams);const dsr=net>0?sumMin(c.cards)/net:0;if(dsr>0.36)out.push({type:"highDebt",priority:dsr>0.5?"high":"med",clientName:`${c.firstName} ${c.lastName}`,detail:`DSR ${(dsr*100).toFixed(0)}%`,task:"High DSR"});}if(settings.reminderAdvisor?.promoExpiring){(c.cards||[]).forEach(card=>{if(card.promo&&card.promoEnd){const dLeft=Math.floor((new Date(card.promoEnd)-today)/86400000);if(dLeft>=0&&dLeft<=60)out.push({type:"promo",priority:dLeft<=14?"high":"med",clientName:`${c.firstName} ${c.lastName}`,detail:`${card.name} — ${dLeft}d`,task:"⏰ Promo Expiring"});}});}if(settings.reminderAdvisor?.debtIncreasing){if(snaps.length>=2&&snaps[snaps.length-1].debt>snaps[0].debt)out.push({type:"debtRising",priority:"med",clientName:`${c.firstName} ${c.lastName}`,detail:`+${fmt(snaps[snaps.length-1].debt-snaps[0].debt)}`,task:"📈 Debt Rising"});}});return out;}

/* ── PRIMITIVES ──────────────────────────────────────────────────────────── */
function Pill({children,color="#94A3B8"}){return<span style={{background:color+"22",color,border:`1px solid ${color}44`,borderRadius:99,padding:"1px 8px",fontSize:11,fontWeight:600,whiteSpace:"nowrap"}}>{children}</span>;}
function InfoTip({text}){const[v,setV]=useState(false);const th=useTh();const c=th.accent;return<span style={{position:"relative",display:"inline-block",marginLeft:4}}><span onMouseEnter={()=>setV(true)} onMouseLeave={()=>setV(false)} style={{display:"inline-flex",alignItems:"center",justifyContent:"center",width:16,height:16,borderRadius:99,fontSize:9,cursor:"help",background:c+"22",color:c,border:`1px solid ${c}44`,fontWeight:700}}>?</span>{v&&<span style={{position:"absolute",bottom:22,left:"50%",transform:"translateX(-50%)",width:240,padding:"10px 12px",borderRadius:10,fontSize:11,lineHeight:1.6,zIndex:999,background:th.modal,border:`1px solid ${th.cardBorder}`,color:th.muted,boxShadow:"0 12px 40px #000a"}}>{text}</span>}</span>;}
function SC({label,value,color,sub}){const th=useTh();return<div style={{...mCARD(th),padding:14,flex:1}}><div style={{fontSize:11,color:th.muted,marginBottom:4}}>{label}</div><div style={{fontSize:18,fontWeight:800,color:color||th.accent}}>{value}</div>{sub&&<div style={{fontSize:10,color:th.dim,marginTop:2}}>{sub}</div>}</div>;}
function Field({label,children}){const th=useTh();return<div style={{marginBottom:14}}><label style={{fontSize:11,color:th.muted,display:"block",marginBottom:5}}>{label}</label>{children}</div>;}
function Row2({children}){const count=Array.isArray(children)?children.filter(Boolean).length:1;return<div style={{display:"grid",gridTemplateColumns:`repeat(${count},1fr)`,gap:12}}>{children}</div>;}
function SHdr({label,right}){const th=useTh();return<div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}><span style={{fontSize:12,fontWeight:700,color:th.accent,letterSpacing:"0.08em",textTransform:"uppercase"}}>{label}</span>{right}</div>;}
function PTag({who,client}){const color=who==="p1"?client.color1:who==="p2"?(client.color2||"#94A3B8"):"#94A3B8";const name=who==="p1"?client.firstName:who==="p2"?(client.partnerFirst||"P2"):"Joint";return<Pill color={color}>{name}</Pill>;}
function SBadge({value,meta,t}){const g=meta.better==="higher"?value>=meta.threshold:value<=meta.threshold;const w=meta.better==="higher"?value>=meta.threshold*0.5:value<=meta.threshold*1.4;const c=g?"#10B981":w?"#F59E0B":"#EF4444";return<Pill color={c}>{g?t.good:w?t.warning:t.critical}</Pill>;}
function Btn({children,onClick,color,small,style={}}){const th=useTh();const c=color||th.accent;return<button onClick={onClick} style={{fontSize:small?11:12,padding:small?"3px 10px":"7px 16px",borderRadius:8,background:c+"22",color:c,border:`1px solid ${c}44`,cursor:"pointer",fontWeight:600,...style}}>{children}</button>;}
function BSolid({children,onClick,style={},color}){const th=useTh();const c=color||th.accent;return<button onClick={onClick} style={{fontSize:12,padding:"7px 20px",borderRadius:8,background:c,color:"#fff",fontWeight:700,border:"none",cursor:"pointer",...style}}>{children}</button>;}
function Tog({label,checked,onChange}){const th=useTh();return<div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}><span style={{fontSize:12,color:th.muted}}>{label}</span><div onClick={()=>onChange(!checked)} style={{width:36,height:20,borderRadius:99,background:checked?th.accent:th.cardBorder,cursor:"pointer",position:"relative",transition:"background 0.2s",flexShrink:0}}><div style={{position:"absolute",top:2,left:checked?18:2,width:16,height:16,borderRadius:99,background:"#fff",transition:"left 0.2s",boxShadow:"0 1px 3px #0004"}}/></div></div>;}
function NumInp({value,onChange,style={},min=0,...rest}){return<input type="number" value={value} onChange={onChange} onFocus={e=>e.target.select()} min={min} style={{...style,MozAppearance:"textfield",appearance:"textfield"}} {...rest}/>;}
function CCircle({value,onChange}){const[open,setOpen]=useState(false);const th=useTh();return<div style={{position:"relative"}}><div onClick={()=>setOpen(o=>!o)} style={{width:34,height:34,borderRadius:"50%",background:value,border:"3px solid white",boxShadow:"0 0 0 1px #0004",cursor:"pointer",flexShrink:0}}/>{open&&<><div onClick={()=>setOpen(false)} style={{position:"fixed",inset:0,zIndex:299}}/><div style={{position:"absolute",top:40,left:0,background:th.modal,border:`1px solid ${th.cardBorder}`,borderRadius:12,padding:10,zIndex:300,boxShadow:"0 16px 40px #000a",width:194}}><div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:5,marginBottom:10}}>{CP.map(c=><div key={c} onClick={()=>{onChange({target:{value:c}});setOpen(false);}} style={{width:28,height:28,borderRadius:"50%",background:c,border:value===c?"3px solid white":"2px solid transparent",cursor:"pointer",boxShadow:"0 0 0 1px #0003"}}/>)}</div><input type="color" value={value} onChange={onChange} style={{width:"100%",height:26,cursor:"pointer",borderRadius:6,border:"none"}}/></div></> }</div>;}
function SSNInput({value,onChange,t}){const[show,setShow]=useState(false);const th=useTh();const fmtSSN=v=>{const d=v.replace(/\D/g,"").slice(0,9);if(d.length<=3)return d;if(d.length<=5)return`${d.slice(0,3)}-${d.slice(3)}`;return`${d.slice(0,3)}-${d.slice(3,5)}-${d.slice(5)}`;};return<div style={{display:"flex",gap:8,alignItems:"center"}}><input type={show?"text":"password"} value={value} onChange={e=>onChange({target:{value:fmtSSN(e.target.value)}})} style={{...mINP(th),flex:1}} placeholder="###-##-####" maxLength={11}/><button onClick={()=>setShow(s=>!s)} style={{fontSize:11,padding:"6px 10px",borderRadius:7,background:th.inp,color:th.muted,border:`1px solid ${th.inpBorder}`,cursor:"pointer",whiteSpace:"nowrap",flexShrink:0}}>{show?t.hideSSN:t.showSSN}</button></div>;}
function CalcRow({label,value,color,big}){const th=useTh();return<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 0",borderBottom:`1px solid ${th.cardBorder}`}}><span style={{fontSize:big?14:12,color:th.muted}}>{label}</span><span style={{fontSize:big?16:13,fontWeight:big?800:600,color:color||th.accent}}>{value}</span></div>;}

/* ── MODAL ───────────────────────────────────────────────────────────────── */
function Modal({title,onClose,children,width=480}){const th=useTh();return<div onClick={e=>e.target===e.currentTarget&&onClose()} style={{position:"fixed",inset:0,background:"#000b",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}><div style={{background:th.modal,border:`1px solid ${th.cardBorder}`,borderRadius:16,padding:24,width:"100%",maxWidth:width,maxHeight:"90vh",overflowY:"auto",boxShadow:"0 32px 80px #000d"}}><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}><span style={{fontSize:14,fontWeight:700,color:th.text}}>{title}</span><button onClick={onClose} style={{background:"none",border:"none",color:th.muted,cursor:"pointer",fontSize:22,lineHeight:1}}>×</button></div>{children}</div></div>;}
function SaveBar({onSave,onCancel,onDelete,t}){const[conf,setConf]=useState(false);const th=useTh();return<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:20,paddingTop:16,borderTop:`1px solid ${th.cardBorder}`}}><div>{onDelete&&!conf&&<button onClick={()=>setConf(true)} style={{fontSize:12,padding:"6px 14px",borderRadius:8,background:"#EF444422",color:"#EF4444",border:"1px solid #EF444444",cursor:"pointer"}}>{t.deleteLabel}</button>}{onDelete&&conf&&<div style={{display:"flex",gap:8,alignItems:"center"}}><span style={{fontSize:11,color:"#EF4444"}}>{t.confirmDelete}</span><button onClick={onDelete} style={{fontSize:12,padding:"5px 12px",borderRadius:8,background:"#EF4444",color:"#fff",border:"none",cursor:"pointer"}}>Yes</button><button onClick={()=>setConf(false)} style={{fontSize:12,padding:"5px 12px",borderRadius:8,background:th.cardBorder,color:th.muted,border:"none",cursor:"pointer"}}>No</button></div>}</div><div style={{display:"flex",gap:8}}><button onClick={onCancel} style={{fontSize:12,padding:"7px 16px",borderRadius:8,background:th.inp,color:th.muted,border:`1px solid ${th.cardBorder}`,cursor:"pointer"}}>{t.cancel}</button><BSolid onClick={onSave}>{t.save}</BSolid></div></div>;}
function IAdd({cols,onSave}){const th=useTh();const[open,setOpen]=useState(false);const[vals,setVals]=useState({});const u=k=>e=>setVals(p=>({...p,[k]:e.target.value}));const save=()=>{if(onSave(vals)){setVals({});setOpen(false);}};if(!open)return<tr onClick={()=>setOpen(true)} style={{cursor:"pointer"}}><td colSpan={cols.length+1} style={{...mTD(th),color:th.dim,fontStyle:"italic",padding:"8px 0"}}>＋ Add row…</td></tr>;return<tr style={{background:th.bg+"88"}}>{cols.map(c=><td key={c.key} style={{...mTD(th),paddingRight:6}}>{c.type==="select"?<select value={vals[c.key]||c.default||""} onChange={u(c.key)} style={{...mIIN(th),padding:"3px 6px"}}>{c.options.map(o=><option key={o.v} value={o.v}>{o.l}</option>)}</select>:<input type={c.type||"text"} placeholder={c.placeholder||""} value={vals[c.key]||""} onChange={u(c.key)} onKeyDown={c.numeric?bE:undefined} style={mIIN(th)} onKeyUp={e=>e.key==="Enter"&&save()}/>}</td>)}<td style={{...mTDR(th),whiteSpace:"nowrap"}}><button onClick={save} style={{fontSize:12,padding:"3px 10px",borderRadius:6,background:GOLD,color:"#0D1B2A",border:"none",cursor:"pointer",fontWeight:700,marginRight:4}}>✓</button><button onClick={()=>setOpen(false)} style={{fontSize:12,padding:"3px 8px",borderRadius:6,background:th.inp,color:th.muted,border:"none",cursor:"pointer"}}>×</button></td></tr>;}

/* ── PROFILE MODAL ───────────────────────────────────────────────────────── */
function ProfileModal({settings,onSave,onClose,t}){const th=useTh();const[s,setS]=useState({...settings});const u=k=>e=>setS(p=>({...p,[k]:e.target.value}));const ZOOMS=[{v:0.9,l:"90%"},{v:1.0,l:"100%"},{v:1.15,l:"115%"},{v:1.25,l:"125%"},{v:1.35,l:"135%"}];const INP=mINP(th);const AccRow=({label,k,presets})=><div style={{marginBottom:14}}><div style={{fontSize:11,color:th.muted,marginBottom:6}}>{label}</div><div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>{presets.map(p=><div key={p.v} onClick={()=>setS(prev=>({...prev,[k]:p.v}))} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2,cursor:"pointer"}}><div style={{width:26,height:26,borderRadius:"50%",background:p.v,border:s[k]===p.v?"3px solid white":"2px solid transparent",boxShadow:s[k]===p.v?`0 0 0 2px ${p.v}`:"0 0 0 1px #0002"}}/><span style={{fontSize:9,color:th.dim}}>{p.l}</span></div>)}<input type="color" value={s[k]||presets[0].v} onChange={e=>setS(p=>({...p,[k]:e.target.value}))} style={{width:26,height:26,cursor:"pointer",border:"none",borderRadius:4}}/><input value={s[k]||''} onChange={e=>setS(p=>({...p,[k]:e.target.value}))} style={{...mIIN(th),width:80,fontFamily:"monospace",fontSize:11}} placeholder="#000000"/></div></div>;return<Modal title={t.profileSettings} onClose={onClose} width={500}><div style={{fontSize:11,fontWeight:700,color:th.dim,marginBottom:8,letterSpacing:"0.07em"}}>DISPLAY SIZE</div><div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap"}}>{ZOOMS.map(z=><button key={z.v} onClick={()=>setS(p=>({...p,zoom:z.v}))} style={{fontSize:12,padding:"6px 14px",borderRadius:8,cursor:"pointer",background:s.zoom===z.v?th.accent+"22":"transparent",color:s.zoom===z.v?th.accent:th.muted,border:`1px solid ${s.zoom===z.v?th.accent:th.cardBorder}`,fontWeight:s.zoom===z.v?700:400}}>{z.l}</button>)}</div><div style={{fontSize:11,fontWeight:700,color:th.dim,marginBottom:8,letterSpacing:"0.07em"}}>CONTACT INFO</div><Row2><Field label="Advisor Name"><input style={INP} value={s.advisorName||""} onChange={u("advisorName")}/></Field><Field label="Email"><input style={INP} value={s.advisorEmail||""} onChange={u("advisorEmail")}/></Field></Row2><Field label="Instagram"><div style={{position:"relative"}}><span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",color:th.dim,fontSize:12}}>@</span><input style={{...INP,paddingLeft:28}} value={s.ig||""} onChange={u("ig")}/></div></Field><div style={{fontSize:11,fontWeight:700,color:th.dim,marginBottom:8,marginTop:4,letterSpacing:"0.07em"}}>THEME COLORS</div><AccRow label={t.darkMode+" Accent"} k="darkAccent" presets={DARK_ACCENTS}/><AccRow label={t.lightMode+" Accent"} k="lightAccent" presets={LIGHT_ACCENTS}/><div style={{fontSize:11,fontWeight:700,color:th.dim,marginBottom:8,marginTop:4,letterSpacing:"0.07em"}}>{t.advisorReminders.toUpperCase()}</div><Tog label="No contact reach-out alert" checked={!!s.reminderAdvisor?.noContact} onChange={v=>setS(p=>({...p,reminderAdvisor:{...p.reminderAdvisor,noContact:v}}))}/>{s.reminderAdvisor?.noContact&&<div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10,paddingLeft:8}}><span style={{fontSize:11,color:th.dim}}>Alert after</span><input type="number" min={7} max={180} value={s.noContactDays||30} onChange={e=>setS(p=>({...p,noContactDays:+e.target.value||30}))} style={{...mIIN(th),width:60,textAlign:"center"}}/><span style={{fontSize:11,color:th.dim}}>days</span></div>}<Tog label="High debt ratio (DSR > 36%)" checked={!!s.reminderAdvisor?.highDebt} onChange={v=>setS(p=>({...p,reminderAdvisor:{...p.reminderAdvisor,highDebt:v}}))}/><Tog label="Promo rates expiring (60 days)" checked={!!s.reminderAdvisor?.promoExpiring} onChange={v=>setS(p=>({...p,reminderAdvisor:{...p.reminderAdvisor,promoExpiring:v}}))}/><Tog label="Clients with increasing debt trend" checked={!!s.reminderAdvisor?.debtIncreasing} onChange={v=>setS(p=>({...p,reminderAdvisor:{...p.reminderAdvisor,debtIncreasing:v}}))}/><SaveBar onSave={()=>onSave(s)} onCancel={onClose} t={t}/></Modal>;}

/* ── NEW CLIENT MODAL (with color chooser) ──────────────────────────────── */
function NewClientModal({onSave,onClose,t}){const th=useTh();const[f,setF]=useState({firstName:"",lastName:"",email:"",color1:"#4472C4"});const[err,setErr]=useState("");const save=()=>{if(!f.firstName||!f.lastName){setErr("First and last name required.");return;}if(!vEmail(f.email)){setErr("Valid email required.");return;}onSave(mig({...f,id:gid()}));};const INP=mINP(th);return<Modal title={t.addClient} onClose={onClose} width={440}><div style={{fontSize:11,color:th.muted,marginBottom:16}}>Fill in the basics — you'll complete the full profile on the Intake tab.</div><Row2><Field label={`${t.firstName} *`}><input style={INP} value={f.firstName} onChange={e=>setF(p=>({...p,firstName:e.target.value}))}/></Field><Field label={`${t.lastName} *`}><input style={INP} value={f.lastName} onChange={e=>setF(p=>({...p,lastName:e.target.value}))}/></Field></Row2><Field label={`${t.email} *`}><input style={INP} value={f.email} onChange={e=>setF(p=>({...p,email:e.target.value}))}/></Field><div style={{display:"flex",alignItems:"center",gap:12,marginBottom:14,padding:"10px 12px",background:th.bg,borderRadius:8}}><CCircle value={f.color1} onChange={e=>setF(p=>({...p,color1:e.target.value}))}/><div><div style={{fontSize:12,fontWeight:600,color:th.text}}>{f.firstName||"Client"} color</div><div style={{fontSize:10,color:th.dim}}>Used for chart identification</div></div></div>{err&&<div style={{fontSize:11,color:"#EF4444",background:"#EF444411",borderRadius:8,padding:"7px 10px",marginBottom:8}}>{err}</div>}<SaveBar onSave={save} onCancel={onClose} t={t}/></Modal>;}

/* ── EDIT CLIENT MODAL ───────────────────────────────────────────────────── */
function ClientForm({client,onSave,onDelete,onClose,t}){const th=useTh();const[f,setF]=useState({firstName:"",lastName:"",partnerFirst:"",partnerLast:"",email:"",phone:"",address:"",dob:"",social:"",clientType:"financeOnly",recommendedBy:"",color1:"#4472C4",color2:"#ED7D31",...(client||{})});const[errs,setErrs]=useState({});const u=k=>e=>setF(p=>({...p,[k]:e.target.value}));const save=()=>{const e={};if(!f.firstName)e.firstName="Required";if(!f.lastName)e.lastName="Required";if(!f.email)e.email="Required";else if(!vEmail(f.email))e.email="Invalid";if(Object.keys(e).length){setErrs(e);return;}onSave(mig({...client,...f,id:client?.id||gid(),partnerFirst:f.partnerFirst||null,partnerLast:f.partnerLast||null,color2:f.partnerFirst?f.color2:null}));};const INP=mINP(th);return<Modal title={t.editClient} onClose={onClose} width={560}><Row2><div><label style={{fontSize:11,color:th.muted,display:"block",marginBottom:5}}>{t.firstName} *</label><input style={INP} value={f.firstName} onChange={u("firstName")}/>{errs.firstName&&<div style={{fontSize:10,color:"#EF4444",marginTop:2}}>{errs.firstName}</div>}</div><div><label style={{fontSize:11,color:th.muted,display:"block",marginBottom:5}}>{t.lastName} *</label><input style={INP} value={f.lastName} onChange={u("lastName")}/>{errs.lastName&&<div style={{fontSize:10,color:"#EF4444",marginTop:2}}>{errs.lastName}</div>}</div></Row2><Row2><Field label={t.partnerFirst}><input style={INP} value={f.partnerFirst||""} onChange={u("partnerFirst")} placeholder="Blank if single"/></Field><Field label={t.partnerLast}><input style={INP} value={f.partnerLast||""} onChange={u("partnerLast")}/></Field></Row2><div><label style={{fontSize:11,color:th.muted,display:"block",marginBottom:5}}>{t.email} *</label><input style={INP} value={f.email} onChange={u("email")}/>{errs.email&&<div style={{fontSize:10,color:"#EF4444",marginTop:2}}>{errs.email}</div>}</div><div style={{height:12}}/><Row2><Field label={t.phone}><input style={INP} value={f.phone||""} onChange={e=>setF(p=>({...p,phone:fmtPh(e.target.value)}))} placeholder="(305) 555-0000"/></Field><Field label={t.dob}><input type="date" style={INP} value={f.dob||""} onChange={u("dob")}/></Field></Row2><Field label={t.address}><input style={INP} value={f.address||""} onChange={u("address")}/></Field><Field label={t.social}><SSNInput value={f.social||""} onChange={u("social")} t={t}/></Field><Row2><Field label={t.clientType}><select style={INP} value={f.clientType||"financeOnly"} onChange={u("clientType")}><option value="financeOnly">{t.financeOnly}</option><option value="financeAndHealth">{t.financeAndHealth}</option></select></Field><Field label={t.recommendedBy}><input style={INP} value={f.recommendedBy||""} onChange={u("recommendedBy")}/></Field></Row2><div style={{display:"flex",gap:24,alignItems:"center",marginBottom:14}}><div style={{display:"flex",alignItems:"center",gap:8}}><CCircle value={f.color1||"#4472C4"} onChange={u("color1")}/><span style={{fontSize:12,color:th.muted}}>{f.firstName||t.p1}</span></div>{f.partnerFirst&&<div style={{display:"flex",alignItems:"center",gap:8}}><CCircle value={f.color2||"#ED7D31"} onChange={u("color2")}/><span style={{fontSize:12,color:th.muted}}>{f.partnerFirst}</span></div>}</div><SaveBar onSave={save} onCancel={onClose} onDelete={onDelete} t={t}/></Modal>;}

/* ── INCOME MODAL (new: popup like bills/cards) ──────────────────────────── */
function IncomeModal({income,client,onSave,onDelete,onClose,t}){const th=useTh();const[f,setF]=useState({person:"p1",label:"",gross:0,net:0,freq:"biweekly",...(income||{})});const u=k=>e=>setF(p=>({...p,[k]:e.target.value}));const persons=[["p1",client.firstName||t.p1],["p2",client.partnerFirst||t.p2],["joint",t.joint]].filter(([k])=>k!=="p2"||client.partnerFirst);const INP=mINP(th);return<Modal title={income?`${t.editLabel} ${t.income}`:t.addIncome} onClose={onClose}><Row2><Field label={t.person}><select style={INP} value={f.person} onChange={u("person")}>{persons.map(([v,l])=><option key={v} value={v}>{l}</option>)}</select></Field><Field label="Label"><input style={INP} value={f.label} onChange={u("label")} placeholder="Job, Business, Rental…"/></Field></Row2><Field label={t.frequency}><select style={INP} value={f.freq} onChange={u("freq")}>{["weekly","biweekly","semimonthly","monthly2","annual"].map(k=><option key={k} value={k}>{t[k]}</option>)}</select></Field><Row2><Field label={`${t.gross} / period ($)`}><NumInp style={INP} value={f.gross} onChange={u("gross")} onKeyDown={bE}/></Field><Field label={`${t.net} / period ($)`}><NumInp style={INP} value={f.net} onChange={u("net")} onKeyDown={bE}/></Field></Row2><div style={{...mCARD(th),padding:12,fontSize:12,display:"flex",gap:24,marginBottom:4}}><span style={{color:th.muted}}>Net/mo: <span style={{color:th.pos,fontWeight:700}}>{fmt(toM(+f.net,f.freq))}</span></span><span style={{color:th.muted}}>Annual: <span style={{color:th.muted,fontWeight:600}}>{fmt(toM(+f.net,f.freq)*12)}</span></span></div><SaveBar onSave={()=>{if(!f.label){alert("Label required.");return;}onSave({...f,id:income?.id||gid(),gross:+f.gross,net:+f.net});}} onCancel={onClose} onDelete={income?onDelete:null} t={t}/></Modal>;}

/* ── CARD MODAL ──────────────────────────────────────────────────────────── */
function CardModal({card,client,onSave,onDelete,onClose,t}){const th=useTh();const[f,setF]=useState({name:"",balance:0,apr:0,min:0,limit:0,promo:false,promoBalance:0,promoRate:0,promoEnd:"",owedBy:"joint",...(card||{})});const[err,setErr]=useState("");const u=k=>e=>setF(p=>({...p,[k]:e.target.type==="checkbox"?e.target.checked:e.target.value}));const save=()=>{if(!f.name){setErr("Name required.");return;}if(f.promo&&+f.promoBalance>+f.balance){setErr("Promo balance > card balance.");return;}onSave({...f,id:card?.id||gid(),balance:+f.balance,apr:+f.apr,min:+f.min,limit:+f.limit,promoBalance:+f.promoBalance,promoRate:+f.promoRate});};const INP=mINP(th);const persons=[["joint","Joint"],[`p1`,client?.firstName||"Person 1"],[`p2`,client?.partnerFirst||"Person 2"]].filter(([k])=>k!=="p2"||client?.partnerFirst);return<Modal title={card?`${t.editLabel} Card`:t.addCard} onClose={onClose}><Field label={t.cardName}><input style={INP} value={f.name} onChange={u("name")}/></Field>{client?.partnerFirst&&<Field label={t.owedByLbl}><select style={INP} value={f.owedBy||"joint"} onChange={u("owedBy")}>{persons.map(([v,l])=><option key={v} value={v}>{l}</option>)}</select></Field>}<Row2><Field label="Balance ($)"><NumInp style={INP} value={f.balance} onChange={u("balance")} onKeyDown={bE}/></Field><Field label="APR (%)"><NumInp style={INP} value={f.apr} onChange={u("apr")} onKeyDown={bE} step="0.1"/></Field></Row2><Row2><Field label="Min Pay ($)"><NumInp style={INP} value={f.min} onChange={u("min")} onKeyDown={bE}/></Field><Field label={<span>Limit ($)<InfoTip text={t.limitInfo}/></span>}><NumInp style={INP} value={f.limit} onChange={u("limit")} onKeyDown={bE}/></Field></Row2><div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14}}><input type="checkbox" id="pr" checked={!!f.promo} onChange={u("promo")} style={{accentColor:th.accent,width:16,height:16,cursor:"pointer"}}/><label htmlFor="pr" style={{fontSize:12,color:th.muted,cursor:"pointer"}}>{t.hasPromo}</label></div>{f.promo&&<><Row2><Field label="Promo Balance ($)"><NumInp style={INP} value={f.promoBalance} onChange={u("promoBalance")} onKeyDown={bE}/></Field><Field label="Promo Rate (%)"><NumInp style={INP} value={f.promoRate} onChange={u("promoRate")} onKeyDown={bE}/></Field></Row2><Field label={t.promoEnd}><input type="date" style={INP} value={f.promoEnd} onChange={u("promoEnd")}/></Field></>}{err&&<div style={{fontSize:11,color:"#EF4444",background:"#EF444411",borderRadius:8,padding:"7px 10px",marginBottom:8}}>{err}</div>}<div style={{...mCARD(th),padding:12,fontSize:12,display:"flex",gap:20,marginBottom:4}}><span style={{color:th.muted}}>Interest/mo: <span style={{color:"#EF4444",fontWeight:700}}>{fmtD((+f.balance)*(+f.apr)/100/12)}</span></span><span style={{color:th.muted}}>Payoff: <span style={{color:GOLD,fontWeight:700}}>{payL(payM(+f.balance,+f.apr,+f.min))}</span></span></div><SaveBar onSave={save} onCancel={onClose} onDelete={card?onDelete:null} t={t}/></Modal>;}

/* ── BILL MODAL ──────────────────────────────────────────────────────────── */
function BillModal({bill,client,onSave,onDelete,onClose,t}){const th=useTh();const[f,setF]=useState({name:"",assignedTo:"joint",cost:0,type:"regular",freq:"monthly2",dueDay:1,dueMonth:1,maturity:"",split:{p1:50,p2:50},...(bill||{})});const u=k=>e=>setF(p=>({...p,[k]:e.target.value}));const persons=[["p1",client.firstName||t.p1],["p2",client.partnerFirst||t.p2],["joint",t.joint]].filter(([k])=>k!=="p2"||client.partnerFirst);const save=()=>{if(!f.name){alert("Name required.");return;}const day=Math.min(31,Math.max(1,+f.dueDay||1));onSave({...f,id:bill?.id||gid(),cost:+f.cost,dueDay:f.type==="annual"?null:day,dueMonth:f.type==="annual"?+f.dueMonth:null,freq:f.type==="annual"?"annual":f.freq});};const INP=mINP(th);const moCost=toM(+f.cost,f.freq);return<Modal title={bill?`${t.editLabel} Bill`:t.addBill} onClose={onClose}><Row2><Field label={t.billName}><input style={INP} value={f.name} onChange={u("name")}/></Field><Field label={t.person}><select style={INP} value={f.assignedTo} onChange={u("assignedTo")}>{persons.map(([v,l])=><option key={v} value={v}>{l}</option>)}</select></Field></Row2><Row2><Field label={t.billType}><select style={INP} value={f.type} onChange={u("type")}>{["regular","annual","temporary"].map(k=><option key={k} value={k}>{t[k]||k}</option>)}</select></Field>{f.type!=="annual"&&<Field label={t.frequency}><select style={INP} value={f.freq} onChange={u("freq")}>{["weekly","biweekly","semimonthly","monthly2"].map(k=><option key={k} value={k}>{t[k]}</option>)}</select></Field>}</Row2><Row2><Field label={t.cost}><NumInp style={INP} value={f.cost} onChange={u("cost")} onKeyDown={bE}/></Field>{f.type!=="annual"?<Field label={t.dueDay}><NumInp style={INP} value={f.dueDay} onChange={e=>setF(p=>({...p,dueDay:Math.min(31,Math.max(1,+e.target.value||1))}))} min={1} max={31} onKeyDown={bE}/></Field>:<Field label="Due Month"><NumInp style={INP} value={f.dueMonth} onChange={u("dueMonth")} min={1} max={12} onKeyDown={bE}/></Field>}</Row2>{f.type==="temporary"&&<Field label="Maturity Date"><input type="date" style={INP} value={f.maturity} onChange={u("maturity")}/></Field>}{f.assignedTo==="joint"&&client.partnerFirst&&<div style={{...mCARD(th),padding:12,marginTop:4,marginBottom:14}}><div style={{fontSize:11,color:th.dim,marginBottom:8}}>⚖️ {t.responsibilitySplit}</div><div style={{display:"flex",alignItems:"center",gap:10}}><span style={{fontSize:12,color:th.text,minWidth:100}}>{client.firstName}: <b>{f.split?.p1??50}%</b> = {fmt(moCost*(f.split?.p1??50)/100)}</span><input type="range" min={0} max={100} value={f.split?.p1??50} onChange={e=>{const v=+e.target.value;setF(p=>({...p,split:{p1:v,p2:100-v}}));}} style={{flex:1,accentColor:th.accent}}/><span style={{fontSize:12,color:th.text,minWidth:100,textAlign:"right"}}>{client.partnerFirst}: <b>{f.split?.p2??50}%</b> = {fmt(moCost*(f.split?.p2??50)/100)}</span></div></div>}<SaveBar onSave={save} onCancel={onClose} onDelete={bill?onDelete:null} t={t}/></Modal>;}

